// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ModelExecutionMetric) predicate.ModelExecutionMetric {
	return predicate.ModelExecutionMetric(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ModelExecutionMetric) predicate.ModelExecutionMetric {
	return predicate.ModelExecutionMetric(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ModelExecutionMetric) predicate.ModelExecutionMetric {
	return predicate.ModelExecutionMetric(sql.NotPredicates(p))
}
